import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function EditLead() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [lead, setLead] = useState(null);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await api.get(`/leads/${id}`);
        setLead(res.data);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load lead");
        navigate("/leads");
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setLead((prev) => ({ ...prev, [name]: value }));
  };

  const update = async (e) => {
    e.preventDefault();
    setSaving(true);

    try {
      await api.put(`/leads/${id}`, {
        name: lead.name,
        contact_number: lead.contact_number,
        email: lead.email,
        lead_source: lead.lead_source,
        status: lead.status,
        interest_level: lead.interest_level,
      });

      alert("Lead updated");
      navigate("/leads");
    } catch (err) {
      // your backend sometimes sends { errors: [...] }
      const msg =
        err.response?.data?.message ||
        (err.response?.data?.errors ? err.response.data.errors.join(", ") : null) ||
        "Update failed";
      alert(msg);
    } finally {
      setSaving(false);
    }
  };

  if (!lead) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div style={{ maxWidth: 480, margin: "20px auto", padding: 20, border: "1px solid #ddd", borderRadius: 8 }}>
      <h2>Edit Lead</h2>

      <form onSubmit={update}>
        <label>Name</label>
        <input
          name="name"
          value={lead.name || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
          required
        />

        <label>Contact Number</label>
        <input
          name="contact_number"
          value={lead.contact_number || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
        />

        <label>Email</label>
        <input
          name="email"
          type="email"
          value={lead.email || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
        />

        <label>Lead Source</label>
        <input
          name="lead_source"
          value={lead.lead_source || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
        />

        <label>Status</label>
        <select
          name="status"
          value={lead.status || "new"}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
        >
          <option value="new">New</option>
          <option value="contacted">Contacted</option>
          <option value="converted">Converted</option>
          <option value="lost">Lost</option>
        </select>

        <label>Interest Level</label>
        <select
          name="interest_level"
          value={lead.interest_level || "low"}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, margin: "6px 0 12px" }}
        >
          <option value="low">Low</option>
          <option value="medium">Medium</option>
          <option value="high">High</option>
        </select>

        <div style={{ display: "flex", gap: 10 }}>
          <button type="submit" disabled={saving} style={{ padding: "10px 14px" }}>
            {saving ? "Saving..." : "Update"}
          </button>

          <button
            type="button"
            onClick={() => navigate("/leads")}
            style={{ padding: "10px 14px" }}
          >
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
}
